import React, { useState, useRef, useEffect } from 'react';
import { createRoot } from 'react-dom/client';
import '../theme/variables.css';

const AI = 'http://localhost:8000';

function useRecorder() {
  const [recording, setRecording] = useState(false);
  const mr = useRef<MediaRecorder|null>(null);
  const chunks = useRef<Blob[]>([]);
  const start = async () => {
    try { const s = await navigator.mediaDevices.getUserMedia({audio:true}); mr.current = new MediaRecorder(s,{mimeType:'audio/webm'}); chunks.current = []; mr.current.ondataavailable = e=>{if(e.data.size>0)chunks.current.push(e.data)}; mr.current.start(); setRecording(true); } catch(e) {}
  };
  const stop = (): Promise<Blob> => new Promise(resolve => {
    if (!mr.current) return;
    mr.current.onstop = () => { resolve(new Blob(chunks.current,{type:'audio/webm'})); mr.current?.stream.getTracks().forEach(t=>t.stop()); };
    mr.current.stop(); setRecording(false);
  });
  return { recording, start, stop };
}

async function transcribe(blob: Blob): Promise<string> { const fd = new FormData(); fd.append('file', blob, 'recording.webm'); const r = await fetch(`${AI}/api/v1/scribe/transcribe`,{method:'POST',body:fd}); return (await r.json()).text||''; }
async function genNote(text: string, ctx: any) { const r = await fetch(`${AI}/api/v1/scribe/generate`,{method:'POST',headers:{'Content-Type':'application/json'},body:JSON.stringify({transcript:text,encounter_type:'visit',patient_context:ctx})}); return r.json(); }
async function billing(dx: string) { const r = await fetch(`${AI}/api/v1/billing/suggest`,{method:'POST',headers:{'Content-Type':'application/json'},body:JSON.stringify({diagnosis:dx})}); return r.json(); }
async function workflow(dx: string) { const r = await fetch(`${AI}/api/v1/workflow/predict`,{method:'POST',headers:{'Content-Type':'application/json'},body:JSON.stringify({diagnosis:dx,assessment:''})}); return r.json(); }

function Badge({variant='neutral',children}:any) { const c:any={success:'#dcfce7,#16a34a',warning:'#fef3c7,#d97706',error:'#fee2e2,#dc2626',info:'#dbeafe,#2563eb',neutral:'#f3f4f6,#6b7280'}; const [bg,cl]=c[variant].split(','); return <span style={{display:'inline-flex',alignItems:'center',padding:'1px 8px',fontSize:11,fontWeight:600,borderRadius:9999,background:bg,color:cl}}>{children}</span>; }
function Button({variant='primary',size='md',loading,disabled,onClick,children,style}:any) { const s:any={primary:{bg:'#2563eb',c:'#fff'},secondary:{bg:'#f3f4f6',c:'#374151',border:'1px solid #d1d5db'},danger:{bg:'#dc2626',c:'#fff'}}; const sz:any={sm:{padding:'6px 12px',fontSize:12},md:{padding:'8px 16px',fontSize:13}}; return <button onClick={onClick} disabled={disabled||loading} style={{background:s[variant].bg,color:s[variant].c,border:s[variant].border||'none',borderRadius:6,fontWeight:500,cursor:disabled?'not-allowed':'pointer',opacity:disabled?0.5:1,...sz[size],...style}}>{loading&&'⏳ '}{children}</button>; }
function Card({title,children,style}:any) { return <div style={{background:'#fff',border:'1px solid #e5e7eb',borderRadius:8,boxShadow:'0 1px 3px rgba(0,0,0,0.06)',overflow:'hidden',...style}}>{title&&<div style={{padding:'10px 14px',borderBottom:'1px solid #f3f4f6',fontSize:13,fontWeight:600,color:'#374151'}}>{title}</div>}<div style={{padding:12}}>{children}</div></div>; }

function Encounter() {
  const [patient, setPatient] = useState<any>(null);
  const [pid, setPid] = useState('');
  const [problems, setProblems] = useState<any[]>([]);
  const [meds, setMeds] = useState<any[]>([]);
  const [allergies, setAllergies] = useState<any[]>([]);
  const [encounters, setEncounters] = useState<any[]>([]);
  const [transcript, setTranscript] = useState('');
  const [soap, setSoap] = useState<any>(null);
  const [bill, setBill] = useState<any>(null);
  const [wf, setWf] = useState<any>(null);
  const [tab, setTab] = useState('scribe');
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState('');
  const [saved, setSaved] = useState(false);
  const { recording, start, stop } = useRecorder();
  const vitals = [{l:'BP',v:'128/82',u:'mmHg'},{l:'HR',v:'72',u:'bpm'},{l:'Temp',v:'37.0',u:'°C'},{l:'O2',v:'98',u:'%'}];

  useEffect(() => {
    const el = document.getElementById('encounter-root');
    const no = el?.dataset.demoNo || '';
    setPid(no);
    if (no) {
      fetch(`${AI}/api/v1/patient/${no}`).then(r=>r.json()).then(d=>{ setPatient(d); setProblems(d.problems||[]); setMeds(d.medications||[]); setAllergies(d.allergies||[]); }).catch(()=>{});
      fetch(`${AI}/api/v1/patient/${no}/encounters`).then(r=>r.json()).then(d=>setEncounters(d.encounters||[])).catch(()=>{});
    }
  }, []);

  const handleRecord = async () => {
    if (recording) { setLoading(true); setError(''); setSaved(false);
      try { const blob = await stop(); const text = await transcribe(blob); setTranscript(text); await process(text); }
      catch(e:any) { setError(e.message); } finally { setLoading(false); }
    } else { start(); }
  };

  const process = async (text: string) => {
    const ctx = { name: patient?.name||'', age: patient?.dob?new Date().getFullYear()-parseInt(patient.dob.substring(0,4)):40, sex: patient?.sex||'U', problems: problems.map((p:any)=>p.name).join(', '), medications: meds.map((m:any)=>m.name).join(', '), allergies: allergies.join(', ') };
    try { const [s,b,w] = await Promise.all([genNote(text,ctx), billing(problems.map((p:any)=>p.name).join(', ')), workflow(problems.map((p:any)=>p.name).join(', '))]); setSoap(s); setBill(b); setWf(w); }
    catch(e:any) { setError('AI error: '+e.message); }
  };

  const handleSave = async () => {
    if (!soap||!pid) return;
    const note = `${soap.subjective||''}\n\nOBJECTIVE:\n${soap.objective||''}\n\nASSESSMENT:\n${soap.assessment||''}\n\nPLAN:\n${soap.plan||''}`;
    try { await fetch(`${AI}/api/v1/patient/${pid}/encounters`,{method:'POST',headers:{'Content-Type':'application/json'},body:JSON.stringify({note,provider_no:patient?.provider_no||'999998',type:'visit'})}); setSaved(true); }
    catch(e:any) { setError('Save failed: '+e.message); }
  };

  const dob = patient?.dob||''; const age = dob?new Date().getFullYear()-parseInt(dob.substring(0,4)):'';

  return (
    <div style={{height:'100vh',display:'flex',flexDirection:'column',fontFamily:'-apple-system,BlinkMacSystemFont,sans-serif',background:'#f3f4f6'}}>
      <div style={{background:'linear-gradient(135deg,#1e3a8a,#2563eb)',color:'#fff',padding:'6px 16px',display:'flex',alignItems:'center',justifyContent:'space-between',boxShadow:'0 2px 8px rgba(0,0,0,0.15)',zIndex:100,minHeight:44}}>
        <div style={{display:'flex',alignItems:'center',gap:12}}>
          <h2 style={{fontSize:15,fontWeight:600,margin:0}}>OSCAR AI Encounter</h2>
          <span style={{fontSize:14,fontWeight:500}}>{patient?.name||'Loading...'}</span>
          <span style={{fontSize:12,opacity:0.8}}>{dob&&`${dob} (${age}y)`} | {patient?.sex} | PHN: {patient?.hin}</span>
        </div>
        <div style={{display:'flex',alignItems:'center',gap:10,fontSize:11}}>
          <a href={`/oscar/demographic/demographiccontrol.jsp?demographic_no=${pid}&displaymode=edit`} target="_blank" style={{color:'rgba(255,255,255,0.85)',textDecoration:'none'}}>Edit Patient</a>
          <a href={`/oscar/oscarEncounter/IncomingEncounter.do?demographicNo=${pid}`} target="_blank" style={{color:'rgba(255,255,255,0.85)',textDecoration:'none',padding:'2px 6px',border:'1px solid rgba(255,255,255,0.3)',borderRadius:4}}>Classic</a>
          <a href="#" onClick={()=>window.open(`/oscar/oscarRx/choosePatient.do?demographicNo=${pid}`,'Rx','width=700,height=1027')} style={{color:'rgba(255,255,255,0.85)',textDecoration:'none'}}>Rx</a>
          <a href="#" onClick={()=>window.open(`/oscar/dms/inboxManage.do?method=prepareForIndexPage&demographicNo=${pid}`,'Labs','width=700,height=900')} style={{color:'rgba(255,255,255,0.85)',textDecoration:'none'}}>Labs</a>
        </div>
      </div>

      <div style={{display:'flex',flex:1,overflow:'hidden'}}>
        <div style={{width:220,background:'#fff',borderRight:'1px solid #e5e7eb',overflow:'auto',padding:'10px 0'}}>
          <Card title="Vitals" style={{margin:'0 6px 8px'}}>
            <div style={{display:'grid',gridTemplateColumns:'1fr 1fr',gap:6}}>{vitals.map((v,i)=><div key={i} style={{textAlign:'center',padding:6,background:'#f9fafb',borderRadius:6}}><div style={{fontSize:20,fontWeight:700,color:'#1f2937'}}>{v.v}</div><div style={{fontSize:10,color:'#6b7280'}}>{v.l} {v.u}</div></div>)}</div>
          </Card>
          <Card title="Problems" style={{margin:'0 6px 8px'}}>
            {problems.length>0?problems.map((p:any,i:number)=><div key={i} style={{display:'flex',justifyContent:'space-between',padding:'3px 0',fontSize:12,borderBottom:'1px solid #f3f4f6'}}><span>{p.name}</span><span style={{color:'#9ca3af',fontFamily:'monospace',fontSize:10}}>{p.code}</span></div>):<div style={{fontSize:11,color:'#9ca3af',textAlign:'center',padding:6}}>None</div>}
          </Card>
          <Card title="Meds" style={{margin:'0 6px 8px'}}>
            {meds.length>0?meds.map((m:any,i:number)=><div key={i} style={{fontSize:11,padding:'3px 0',borderBottom:'1px solid #f3f4f6'}}><strong>{m.name}</strong></div>):<div style={{fontSize:11,color:'#9ca3af',textAlign:'center',padding:6}}>None</div>}
          </Card>
          <Card title="Allergies" style={{margin:'0 6px 8px'}}>
            <div style={{display:'flex',gap:3,flexWrap:'wrap'}}>{allergies.length>0?allergies.map((a:any,i:number)=><Badge key={i} variant="warning">{typeof a==='string'?a:a.name}</Badge>):<span style={{fontSize:11,color:'#9ca3af'}}>None</span>}</div>
          </Card>
          {encounters.length>0&&<Card title="Past Encounters" style={{margin:'0 6px 8px'}}>
            {encounters.slice(0,5).map((e:any,i:number)=><div key={i} style={{fontSize:11,padding:'3px 0',borderBottom:'1px solid #f3f4f6'}}><div style={{color:'#6b7280'}}>{e.date?.substring(0,10)} — {e.type}</div><div style={{color:'#374151',maxHeight:32,overflow:'hidden'}}>{e.note?.substring(0,60)}...</div></div>)}
          </Card>}
        </div>

        <div style={{flex:1,display:'flex',flexDirection:'column',overflow:'hidden'}}>
          <div style={{background:'#fff',borderBottom:'1px solid #e5e7eb',padding:'8px 14px',display:'flex',alignItems:'center',gap:10}}>
            <Button onClick={handleRecord} variant={recording?'danger':'primary'} size="sm" disabled={loading}>
              {recording?<span style={{display:'inline-block',width:8,height:8,borderRadius:'50%',background:'#fff',marginRight:6,animation:'pulse 1s infinite'}}/>:'▶'} {recording?'Stop':'Record'}
            </Button>
            <input value={transcript} onChange={e=>setTranscript(e.target.value)} placeholder="Or paste transcript then generate..." style={{flex:1,padding:'6px 10px',border:'1px solid #d1d5db',borderRadius:6,fontSize:13}} />
            <Button onClick={()=>process(transcript)} disabled={!transcript||loading} variant="secondary" size="sm">Generate</Button>
            {error&&<span style={{color:saved?'#16a34a':'#dc2626',fontSize:12,fontWeight:500}}>{error}</span>}
          </div>

          <div style={{flex:1,overflow:'auto',padding:14}}>
            {!soap&&!loading&&!transcript&&<div style={{textAlign:'center',padding:80,color:'#9ca3af'}}><div style={{fontSize:48,marginBottom:16}}>🎙️</div><div style={{fontSize:18,fontWeight:500}}>Start an Encounter</div><div style={{fontSize:14,marginTop:4}}>Click Record or paste a transcript to begin.</div></div>}
            {!soap&&!loading&&transcript&&<Card title="Transcript"><div style={{whiteSpace:'pre-wrap',fontSize:14,lineHeight:1.6,color:'#374151'}}>{transcript}</div></Card>}
            {loading&&<div style={{textAlign:'center',padding:80,color:'#6b7280'}}><div style={{fontSize:20,fontWeight:500,marginBottom:12}}>{recording?'Recording...':'Processing...'}</div><div style={{width:36,height:36,border:'3px solid #e5e7eb',borderTopColor:'#2563eb',borderRadius:'50%',margin:'0 auto',animation:'spin 0.8s linear infinite'}}/></div>}

            {soap&&<div>
              <div style={{display:'flex',gap:0,borderBottom:'2px solid #e5e7eb',marginBottom:16}}>
                {[{k:'scribe',n:'SOAP Note'},{k:'billing',n:`Billing (${bill?.suggestions?.length||0})`},{k:'workflow',n:'Actions'}].map(t=><button key={t.k} onClick={()=>setTab(t.k)} style={{padding:'8px 16px',background:'none',border:'none',borderBottom:tab===t.k?'2px solid #2563eb':'2px solid transparent',marginBottom:-2,color:tab===t.k?'#2563eb':'#6b7280',fontWeight:tab===t.k?600:400,cursor:'pointer',fontSize:13}}>{t.n}</button>)}
              </div>

              {tab==='scribe'&&<div style={{display:'flex',flexDirection:'column',gap:12}}>
                <Editable label="Subjective" value={soap.subjective} onChange={(v:string)=>setSoap({...soap,subjective:v})} />
                <Editable label="Objective" value={soap.objective} onChange={(v:string)=>setSoap({...soap,objective:v})} />
                <Editable label="Assessment" value={soap.assessment} onChange={(v:string)=>setSoap({...soap,assessment:v})} />
                <Editable label="Plan" value={soap.plan} onChange={(v:string)=>setSoap({...soap,plan:v})} />
                <div style={{display:'flex',gap:8,marginTop:8}}>
                  <Button onClick={handleSave} variant="primary">{saved?'Saved ✓':'Save to Oscar'}</Button>
                  <Button onClick={()=>{setSoap(null);setTranscript('');setSaved(false);}} variant="secondary">New Encounter</Button>
                </div>
              </div>}

              {tab==='billing'&&bill?.suggestions?.map((b:any,i:number)=><div key={i} style={{display:'flex',justifyContent:'space-between',alignItems:'center',padding:10,borderBottom:'1px solid #f3f4f6'}}><div><strong style={{fontSize:16}}>{b.code}</strong> <span style={{color:'#6b7280',fontSize:14}}>{b.description}</span><div style={{fontSize:11,color:'#9ca3af'}}>{b.rationale}</div></div><div style={{textAlign:'right'}}><strong style={{fontSize:16,color:'#2563eb'}}>${b.fee?.toFixed(2)}</strong><div><Badge variant={b.confidence>=0.85?'success':'warning'}>{Math.round(b.confidence*100)}%</Badge></div></div></div>)}
              {tab==='billing'&&!bill?.suggestions?.length&&<p style={{color:'#9ca3af',textAlign:'center',padding:20}}>No billing suggestions</p>}

              {tab==='workflow'&&wf&&<div style={{display:'flex',flexDirection:'column',gap:16}}>
                {wf.prescriptions?.length>0&&<Card title="Prescriptions">{wf.prescriptions.map((p:any,i:number)=><div key={i} style={{padding:8,borderBottom:'1px solid #f3f4f6',fontSize:13}}><strong>{p.drug} {p.dose}</strong> — {p.route} {p.frequency} x {p.duration}<div style={{fontSize:11,color:'#6b7280'}}>{p.rationale}</div></div>)}</Card>}
                {wf.lab_orders?.length>0&&<Card title="Labs">{wf.lab_orders.map((l:any,i:number)=><div key={i} style={{display:'flex',justifyContent:'space-between',padding:8,borderBottom:'1px solid #f3f4f6',fontSize:13}}><span>{l.test} — {l.rationale}</span><Badge variant={l.urgency==='stat'?'error':l.urgency==='urgent'?'warning':'info'}>{l.urgency}</Badge></div>)}</Card>}
                {wf.referrals?.length>0&&<Card title="Referrals">{wf.referrals.map((r:any,i:number)=><div key={i} style={{padding:8,borderBottom:'1px solid #f3f4f6',fontSize:13}}><strong>{r.specialty}</strong><div style={{fontSize:11,color:'#6b7280'}}>{r.rationale}</div></div>)}</Card>}
              </div>}
            </div>}
          </div>
        </div>
      </div>
      <style>{'@keyframes pulse{0%,100%{opacity:1}50%{opacity:0.3}}@keyframes spin{to{transform:rotate(360deg)}}'}</style>
    </div>
  );
}

function Editable({label,value,onChange}:{label:string;value:string;onChange:(v:string)=>void}) { return <div><h4 style={{fontSize:13,fontWeight:600,color:'#1d4ed8',marginBottom:4}}>{label}</h4><textarea value={value} onChange={e=>onChange(e.target.value)} rows={3} style={{width:'100%',padding:8,fontSize:13,border:'1px solid #d1d5db',borderRadius:6,fontFamily:'inherit',resize:'vertical',background:'#fff'}}/></div>; }

const el = document.getElementById('encounter-root');
if (el) createRoot(el).render(<Encounter />);
